-- ============================================================================
-- Japan travelers seed — mid-high tier (20 people → 73 unit rows)
--
-- One row per 2D1N/3D2N leg. Multi-city travelers repeat (same name/phone/notes,
-- different city+dates), linked by meta.person_id + meta.unit_order/unit_total.
-- Tagged meta.market='japan' + meta.seed_batch='jp-01' (filterable + wipeable).
--
-- Budget is YEN (France mid-high logic × ¥183). Stored in the legacy *_eur meta
-- keys + budget_per_day/hotel_budget columns (renderer just prefixes ¥, no
-- conversion). Commission planner_payout = ¥7,300 / unit. Dates Aug 1–16 2026
-- (adjust per-traveler later); destinations span seasons on purpose.
--
-- Rollback:  DELETE FROM public.travelers WHERE meta->>'seed_batch' = 'jp-01';
-- Safe to re-run (the DO block below clears jp-01 first).
-- ============================================================================

ALTER TABLE public.travelers ADD COLUMN IF NOT EXISTS meta          jsonb;
ALTER TABLE public.travelers ADD COLUMN IF NOT EXISTS budget_per_day int;
ALTER TABLE public.travelers ADD COLUMN IF NOT EXISTS hotel_budget   int;
ALTER TABLE public.travelers ADD COLUMN IF NOT EXISTS market         text;

-- Re-run cleanup: remove any prior jp-01 rows + their cascade artefacts.
DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM information_schema.columns
             WHERE table_schema='public' AND table_name='travelers' AND column_name='meta') THEN
    DELETE FROM public.itinerary_items WHERE plan_id IN (
      SELECT id FROM public.plans WHERE traveler_id IN (
        SELECT id FROM public.travelers WHERE meta->>'seed_batch' = 'jp-01'));
    DELETE FROM public.plans WHERE traveler_id IN (
      SELECT id FROM public.travelers WHERE meta->>'seed_batch' = 'jp-01');
    DELETE FROM public.travelers WHERE meta->>'seed_batch' = 'jp-01';
  END IF;
END $$;

-- Mirror market onto a top-level column too (in case the admin filter prefers it).
INSERT INTO public.travelers
  (id, name, phone, destination, traveler_type, arrival_date, arrival_time, duration, group_size, special_notes, status, planner_payout, requires_bond, bond_amount, budget_per_day, hotel_budget, meta) VALUES
('b0000001-0000-4000-8000-000100010000','Beatriz Fonseca','+55 21 98471-3625','Tokyo','solo','2026-08-03','14:15','3D2N',1,'I shoot architecture and quiet streets for a living, and Japan has been the cover of my mood board since art school in Rio. I do not want the postcard angle everyone already has — I want the side street, the cedar forest at Nikko at dawn, the moment before a temple opens. Build me mornings around golden hour and let me wander unhurried; the camera is how I think.','unassigned',7300,false,NULL,35000,37500,
 '{"seed_batch":"jp-01","market":"japan","person_id":"0001","unit_order":1,"unit_total":4,"trip_start_date":"2026-08-03","trip_end_date":"2026-08-09","trip_total_duration":"7D6N","origin_country":"Brazil","origin_city":"Rio de Janeiro","ages":[34],"languages":["Portuguese","English (fluent)","Spanish (conversational)"],"occasion":"Solo creative reset after finishing a long photo book project","budget_tier":"mid_range","daily_spend_per_pax_eur":35000,"hotel_budget_per_night_eur":37500,"hotel_budget_per_night_pax_eur":37500,"pace":"active","splurge_willingness":"one_two_splurges","dietary_restrictions":"none","mobility":"Fully mobile, happy to walk 15-20km a day chasing light and angles","interests":["photography","temples_shrines","architecture","hidden_gems","gardens"],"must_avoid":"Packaged group bus tours and midday tourist crushes that ruin the light","previous_visits_japan":"first_time","booking_authority":"planner_recommends","accommodation_preference":"Stylish design hotels in walkable old neighborhoods; one traditional ryokan night near nature would be a dream for sunrise shots"}'::jsonb),
