('b0000001-0000-4000-8000-000200010000','Henrik Lundgren','+47 936 24 718','Sapporo','solo','2026-08-01','13:45','3D2N',1,'Back home in Norway I hike fjords on every day off, so people are surprised I picked Japan — but Hokkaido is the one landscape I have never been able to stop reading about. I want lavender fields, volcanic ridgelines, and a long quiet soak after each hike with no one talking to me. A Yoichi whisky stop near Hakodate would be the perfect full stop on the trip.','unassigned',7300,false,NULL,36500,43500,
 '{"seed_batch":"jp-01","market":"japan","person_id":"0002","unit_order":1,"unit_total":3,"trip_start_date":"2026-08-01","trip_end_date":"2026-08-06","trip_total_duration":"6D5N","origin_country":"Norway","origin_city":"Oslo","ages":[47],"languages":["Norwegian","English (fluent)","Swedish (conversational)"],"occasion":"Milestone solo trip the year before turning 48, chasing northern landscapes that aren''t his own","budget_tier":"mid_range","daily_spend_per_pax_eur":36500,"hotel_budget_per_night_eur":43500,"hotel_budget_per_night_pax_eur":43500,"pace":"active","splurge_willingness":"frequent","dietary_restrictions":"none","mobility":"Fit hiker, comfortable with full-day trails and elevation; manages a slightly stiff lower back so prefers no overnight bus transfers","interests":["nature_hiking","onsen","photography","sake_whisky","local_culture"],"must_avoid":"Crowded city nightlife and rushed multi-stop days; he came for open space and quiet","previous_visits_japan":"first_time","booking_authority":"planner_books_all","accommodation_preference":"Onsen ryokan with outdoor baths and mountain or sea views; will happily pay up for the room with the best soak"}'::jsonb),
